    for word_count in word_counts:
        for word, count in word_count.items():
            if word in counts:
                counts[word] += count
            else:
                counts[word] = count

    top_5 = sorted(counts.items(), key=lambda x: x[1], reverse=True)[:5]
    for word, count in top_5:
        print(f'{word}: {count}')

if __name__ == '__main__':
    main()
```
